4578 /// Try to simplify a select instruction when its condition operand is an
4579 /// integer comparison where one operand of the compare is a constant.
4580 static Value *simplifySelectBitTest(Value *TrueVal, Value *FalseVal, Value *X,
4581                                     const APInt *Y, bool TrueWhenUnset) {
4582   const APInt *C;
4583 
4584   // (X & Y) == 0 ? X & ~Y : X  --> X
4585   // (X & Y) != 0 ? X & ~Y : X  --> X & ~Y
4586   if (FalseVal == X && match(TrueVal, m_And(m_Specific(X), m_APInt(C))) &&
4587       *Y == ~*C)
4588     return TrueWhenUnset ? FalseVal : TrueVal;
4589 
4590   // (X & Y) == 0 ? X : X & ~Y  --> X & ~Y
4591   // (X & Y) != 0 ? X : X & ~Y  --> X
4592   if (TrueVal == X && match(FalseVal, m_And(m_Specific(X), m_APInt(C))) &&
4593       *Y == ~*C)
4594     return TrueWhenUnset ? FalseVal : TrueVal;
4595 
4596   if (Y->isPowerOf2()) {
4597     // (X & Y) == 0 ? X | Y : X  --> X | Y
4598     // (X & Y) != 0 ? X | Y : X  --> X
4599     if (FalseVal == X && match(TrueVal, m_Or(m_Specific(X), m_APInt(C))) &&
4600         *Y == *C) {
4601       // We can't return the or if it has the disjoint flag.
4602       if (TrueWhenUnset && cast<PossiblyDisjointInst>(TrueVal)->isDisjoint())
4603         return nullptr;
4604       return TrueWhenUnset ? TrueVal : FalseVal;
4605     }
4606 
4607     // (X & Y) == 0 ? X : X | Y  --> X
4608     // (X & Y) != 0 ? X : X | Y  --> X | Y
4609     if (TrueVal == X && match(FalseVal, m_Or(m_Specific(X), m_APInt(C))) &&
4610         *Y == *C) {
4611       // We can't return the or if it has the disjoint flag.
4612       if (!TrueWhenUnset && cast<PossiblyDisjointInst>(FalseVal)->isDisjoint())
4613         return nullptr;
4614       return TrueWhenUnset ? TrueVal : FalseVal;
4615     }
4616   }
4617 
4618   return nullptr;
4619 }
