4621 static Value *simplifyCmpSelOfMaxMin(Value *CmpLHS, Value *CmpRHS,
4622                                      CmpPredicate Pred, Value *TVal,
4623                                      Value *FVal) {
4624   // Canonicalize common cmp+sel operand as CmpLHS.
4625   if (CmpRHS == TVal || CmpRHS == FVal) {
4626     std::swap(CmpLHS, CmpRHS);
4627     Pred = ICmpInst::getSwappedPredicate(Pred);
4628   }
4629 
4630   // Canonicalize common cmp+sel operand as TVal.
4631   if (CmpLHS == FVal) {
4632     std::swap(TVal, FVal);
4633     Pred = ICmpInst::getInversePredicate(Pred);
4634   }
4635 
4636   // A vector select may be shuffling together elements that are equivalent
4637   // based on the max/min/select relationship.
4638   Value *X = CmpLHS, *Y = CmpRHS;
4639   bool PeekedThroughSelectShuffle = false;
4640   auto *Shuf = dyn_cast<ShuffleVectorInst>(FVal);
4641   if (Shuf && Shuf->isSelect()) {
4642     if (Shuf->getOperand(0) == Y)
4643       FVal = Shuf->getOperand(1);
4644     else if (Shuf->getOperand(1) == Y)
4645       FVal = Shuf->getOperand(0);
4646     else
4647       return nullptr;
4648     PeekedThroughSelectShuffle = true;
4649   }
4650 
4651   // (X pred Y) ? X : max/min(X, Y)
4652   auto *MMI = dyn_cast<MinMaxIntrinsic>(FVal);
4653   if (!MMI || TVal != X ||
4654       !match(FVal, m_c_MaxOrMin(m_Specific(X), m_Specific(Y))))
4655     return nullptr;
4656 
4657   // (X >  Y) ? X : max(X, Y) --> max(X, Y)
4658   // (X >= Y) ? X : max(X, Y) --> max(X, Y)
4659   // (X <  Y) ? X : min(X, Y) --> min(X, Y)
4660   // (X <= Y) ? X : min(X, Y) --> min(X, Y)
4661   //
4662   // The equivalence allows a vector select (shuffle) of max/min and Y. Ex:
4663   // (X > Y) ? X : (Z ? max(X, Y) : Y)
4664   // If Z is true, this reduces as above, and if Z is false:
4665   // (X > Y) ? X : Y --> max(X, Y)
4666   ICmpInst::Predicate MMPred = MMI->getPredicate();
4667   if (MMPred == CmpInst::getStrictPredicate(Pred))
4668     return MMI;
4669 
4670   // Other transforms are not valid with a shuffle.
4671   if (PeekedThroughSelectShuffle)
4672     return nullptr;
4673 
4674   // (X == Y) ? X : max/min(X, Y) --> max/min(X, Y)
4675   if (Pred == CmpInst::ICMP_EQ)
4676     return MMI;
4677 
4678   // (X != Y) ? X : max/min(X, Y) --> X
4679   if (Pred == CmpInst::ICMP_NE)
4680     return X;
4681 
4682   // (X <  Y) ? X : max(X, Y) --> X
4683   // (X <= Y) ? X : max(X, Y) --> X
4684   // (X >  Y) ? X : min(X, Y) --> X
4685   // (X >= Y) ? X : min(X, Y) --> X
4686   ICmpInst::Predicate InvPred = CmpInst::getInversePredicate(Pred);
4687   if (MMPred == CmpInst::getStrictPredicate(InvPred))
4688     return X;
4689 
4690   return nullptr;
4691 }
